{
  "name": "MassHealth Medicare Savings Program",
  "eligibility": {
    "age": null,
    "income_limits": "Must be a Medicare beneficiary (typically age 65+ or under 65 with certain disabilities). Countable income at or below 225% of the Federal Poverty Level (FPL), which changes yearly on March 1. For 2025: $2,993/month for a single individual; $4,058/month for a married couple. Higher incomes may qualify for full MassHealth if assets meet limits. Under age 65 on MassHealth Standard may qualify without asset test.[1][2][3][5]",
    "asset_limits": "No asset limit for MSP-only eligibility (effective March 1, 2024; home and savings not counted). For combined MSP and certain MassHealth benefits: $2,000 for single applicants, $3,000 for married couples.[2][3][4][5]",
    "other_requirements": ["Massachusetts resident.", "Enrolled in Medicare (Part A and/or B).", "Meet MassHealth immigration criteria.", "For full MassHealth + MSP: Meet rules for MassHealth Standard or CommonHealth if income ≤225% FPL.[1][2][3]"]
  },
  "benefits": {
    "type": "financial",
    "value": "Pays Medicare premiums (Part A and/or B), deductibles, coinsurance, copays (full for QMB; Part B premium only for SLMB/QI). Includes automatic enrollment in Medicare Part D Extra Help for prescription drugs. Provides Health Safety Net coverage at acute care hospitals and community health centers (CHCs). QMB: Pays all Part A/B costs. SLMB/QI: Part B premium only. Saves up to $3,000/year.[2][4]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: MassHealth portal (mass.gov for application).", "Phone: MassHealth Customer Service Center (call for details).", "Mail: MassHealth Enrollment Center (address on application form).", "Download and submit PDF application from mass.gov.[2][5]"],
    "processing_time": "Notice about decision within 30 days.[5]",
    "waitlist": null,
    "forms": ["Medicare Savings Programs Application (attached to mass.gov/doc/medicare-savings-programs-application/download).", "Massachusetts Application for Health and Dental Coverage and Help Paying Costs (ACA-3) for MSP + MassHealth.[3][5]"],
    "documents": ["Proof of income.", "Proof of Medicare enrollment.", "Proof of residency.", "Information about spouse if applicable.", "SNAP rights acknowledged if applying (optional).[5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": null,
    "offices_or_providers": null
  },
  "official_source": "https://www.mass.gov/info-details/get-help-paying-medicare-costs",
  "gotchas": ["No asset test only for MSP-only; assets checked for combined MassHealth benefits.", "Income limits update yearly on March 1—verify current FPL.", "Must be on Medicare; not for MassHealth-only.", "QMB provides more benefits (full cost coverage) than SLMB/QI (premium only)—state assigns tier.", "Do not need MassHealth to qualify for MSP.", "Under 65 on MassHealth Standard: income test applies, no assets.[1][2][3][4]"],
  "data_shape_notes": "Tiered by QMB (full coverage), SLMB/QI (premiums only); no asset test for MSP-only since 2024; income at 225% FPL; scales minimally by household size (single/couple shown); statewide uniform."
}

{
  "name": "SNAP (Food Stamps)",
  "eligibility": {
    "age": 60,
    "income_limits": "For households with a member 60+ or disabled (Oct 1, 2025–Sept 30, 2026): Gross income limit at 200% FPL - 1 person: $2608/month; 2: $3526; 3: $4442; 4: $5358; 5: $6276; 6: $7192; 7: $8108; +$916 each additional. If over gross, may qualify via net income test (gross income minus deductions). Households with elderly/disabled only need net income test if failing gross. Alternative federal rules if failing gross: $15,060/year (1 person) or $20,440 (2 people) net income limit, no gross limit.[1][4][7]",
    "asset_limits": "No asset limit in Massachusetts (home and vehicles exempt). If household has member 60+ or disabled and fails gross income test, may qualify under federal rules with $4,500 asset limit (countable resources like bank accounts; home/vehicles not counted).[1]",
    "other_requirements": ["U.S. citizen or qualified non-citizen (immigrants/refugees may face stricter checks or loss of eligibility per recent federal changes).", "Must live in Massachusetts.", "Household includes those who buy/prepare food together.", "Recent federal changes (One Big Beautiful Bill Act of 2025) add work requirements (80 hours/month work/volunteer/training) for ages 55-64 without dependents; stricter for 60-65, affecting ~99,000 in MA with documentation risks. Some exemptions for caregivers/disabled.", "No earned income requirement for some elderly/disabled/child-only households.", "Medical expenses deductible for elderly/disabled."][1][2][3][5][6][7]
  },
  "benefits": {
    "type": "financial",
    "value": "Monthly EBT card benefits for food purchases at grocers. Average for MA seniors: $147/month. Amount based on net income (~$100 more net income = $30 less benefits); minimum/maximum allotments apply. Varies by deductions (e.g., shelter, medical, utilities). Issued back to application date if approved.[1][2][3]",
    "varies_by": "household_size"
  },
  "application": {
    "methods": ["Online: DTA Connect (implied via mass.gov/DTA).", "Phone: 1-833-712-8027 (8:15 AM–4:45 PM Mon-Fri for interview).", "Mail/Download: SNAP Application for Seniors (form 09-160-1221-05) from mass.gov.", "In-person: Local DTA offices (via mass.gov/DTA locations)."][3][8]],
    "processing_time": "Standard: 30 days. Expedited (emergency): 7 days if gross income + bank < monthly housing OR gross < $150 + bank ≤$100 OR migrant + bank ≤$100.[3]",
    "waitlist": null,
    "forms": ["SNAP Application for Seniors (09-160-1221-05) for individuals/couples 60+."][3][8]],
    "documents": ["Proof of income (Social Security, pensions, etc.).", "Proof of expenses: medical (bills/receipts for elderly/disabled), shelter, utilities, child support/care.", "ID, residency proof. Minimal for initial: name, address, signature accepted; call for interview.[3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered uniformly by DTA statewide; possible regional processing differences via local offices, but no specified variations in rules/benefits.[3]",
    "offices_or_providers": ["Local DTA offices (find via mass.gov/DTA). Senior centers/COAs as outreach partners.[5]"]
  },
  "official_source": "https://www.mass.gov/lists/snap-application-for-seniors",
  "gotchas": ["Elderly/disabled households skip gross income test (only net), but recent 2025 federal law adds work/docs for 55-65, risking loss for 99k in MA + reduced utility aid for 45k; immigrants hit hardest.", "No asset limit in MA (expanded eligibility), but federal fallback has $4500 if failing gross.", "Deduct medical/shelter costs anytime for more benefits—often missed.", "Apply even if over gross; net test may qualify. Half of eligible seniors don't apply.", "Benefits only for food; EBT card info provided upon approval.[1][2][3][4][6]"],
  "data_shape_notes": "MA expands federal SNAP with no asset limit, 200% FPL gross for elderly/disabled (net only if fail gross); benefits scale by household size/net income/deductions; recent federal work changes disproportionately affect 60-65; expedited for low-income/cash."
}

{
  "name": "Fuel Assistance (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Household gross annual income cannot exceed 60% of Massachusetts' estimated State Median Income (FY 2026). Maximum levels by household size: 1: $51,777; 2: $67,709; 3: $83,641; 4: $99,573; 5: $115,504; 6: $131,436; 7: $127,720-$134,423; 8: $134,423-$137,410; 9: $137,410; 10: $140,397. For households with heat included in rent, must pay over 30% of income toward rent to qualify for subsidy.[2][3][4]",
    "asset_limits": "No asset limits mentioned in program guidelines.[2][4]",
    "other_requirements": ["Reside in Massachusetts", "Eligibility based on household size and combined gross annual income of members 18+", "Homeowners and renters eligible, including those with heat included in rent", "Contact local agency for full criteria as income is not the only factor", "Must reapply each year"][2][3][4][6]
  },
  "benefits": {
    "type": "financial",
    "value": "Fixed benefit amount paid directly to heating vendor for primary energy needs (oil, electricity, natural gas, propane, kerosene, wood, coal) from November 1 to April 30. Renters with heat included may receive monthly subsidy November to April. Exact benefit levels vary; see FY 2026 LIHEAP Income Eligibility and Benefit Chart from local agency.[1][2][3]",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online: HEAP portal at https://www.toapply.org/MassHEAP (opens October 1 for heating season November 1-April 30)", "In-person: At local LIHEAP agency (find via portal, Cold Relief Heatline 800-632-8175, or FY 2026 Cold Relief Brochure)", "Phone: Varies by agency (e.g., Boston/Brookline/Newton: 617.357.6012; Malden/Medford area: 781.322.6284; general: 800-632-8175)", "Mail: To local agency or use recertification envelope if received"][2][3][4],
    "processing_time": "Not specified; contact local agency.[2]",
    "waitlist": null,
    "forms": ["Recertification application (if received by mail)", "Printable forms from local agency sites (e.g., ABCD)", "FY 2026 LIHEAP application via online portal"][2][3],
    "documents": ["Photo ID for head of household (e.g., driver's license)", "List of all household members", "Heating bills (company name, account number)", "Housing info (lease or mortgage statement)", "Proof of income for 30 days prior to application (wages, pension, etc.)"][2][4]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide but administered by local agencies.",
    "regional_variations": "Administered by different local agencies/providers by region (e.g., Valley Opportunity Council in Hampden County; ABCD in Boston area; Self Help Inc. in other areas). Phone numbers, offices, and exact processes vary by locality. Some regions have specific offices (e.g., Chicopee: 413-552-1548; Holyoke).[1][3]",
    "offices_or_providers": ["Use HEAP portal, Cold Relief Heatline (800-632-8175), or brochure to find local agency by town"][1][2][4]
  },
  "official_source": "https://www.mass.gov/how-to/apply-for-home-heating-and-energy-assistance",
  "gotchas": ["Must reapply every year even if previously approved", "Income based on gross annual for all members 18+; not just public assistance recipients", "Heat-in-rent households need to pay >30% income on rent", "Application opens October 1; deadline April 30", "Over-income households may qualify for Mass Save Moderate Income program instead (call 1-866-527-7283)", "Local agency determines full eligibility beyond income"][1][2][3][6],
  "data_shape_notes": "Administered statewide by local agencies with region-specific contacts; income max at 60% state median by household size; fixed seasonal vendor payments with variations by fuel type, rent subsidy rules, and unpublished benefit tiers"
}

{
  "name": "SHINE (Serving Health Insurance Needs of Everyone)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits for SHINE counseling itself; available to all Massachusetts residents eligible for Medicare (typically age 65+) or approaching eligibility, including those with limited income for related programs like Medicare Savings Programs (QMB, SLMB, QI), MassHealth, Extra Help/LIS, and Prescription Advantage. Counselors screen for these programs' specific income guidelines, but exact dollar amounts not specified in sources.",
    "asset_limits": "No asset limits for SHINE; applies to screened programs like Medicare Savings Programs where counselors explain guidelines, but details on countable assets/exemptions not provided.",
    "other_requirements": ["Massachusetts resident", "Eligible for Medicare or approaching eligibility", "Includes elders, individuals with disabilities, and caregivers"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free, unbiased health insurance information, counseling, and assistance covering Medicare Parts A/B/D, Medicare Advantage (HMO/PPO), Medigap, prescription drug plans, MassHealth/Medicaid, Medicare Savings Programs (QMB/SLMB/QI), Extra Help/LIS, Prescription Advantage, retiree plans, and other options for limited resources. Counselors screen eligibility, help with applications/enrollment, compare costs/benefits, and explain timelines. Provided in-person, phone, email, mail, or virtual.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Call MassOptions at 1-800-243-4636 or local SHINE lead; email SHINE@mass.gov", "In-person: Senior centers, Councils on Aging, Regional Aging Services Access Points, or local providers (e.g., Ethos in Boston at 617-522-9270, Mystic Valley Elder Services at 781-388-4845, Mattapoisett at 508-758-4110)", "Online referral: Some local sites like Mystic Valley Elder Services have referral forms", "Other: Counselors assist with applications for related programs like MassHealth"],
    "processing_time": "SHINE counselor contact/return call typically within 2 business days at some sites; no standard statewide timeline specified.",
    "waitlist": null,
    "forms": ["No specific SHINE application form; uses referral or direct contact. Counselors help access applications for programs like MassHealth, Medicare Savings Programs, Extra Help/LIS, Prescription Advantage"],
    "documents": ["Not specified for SHINE counseling; prepare Medicare card, income details, insurance info for eligibility screening and related program applications"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Massachusetts residents only",
    "regional_variations": "Delivered through local providers including elder service agencies, Councils on Aging, community organizations (e.g., Ethos in Boston, AgeSpan, Access Care Partners, Mystic Valley Elder Services serving specific communities like Chelsea/Everett/Lynn; Mattapoisett; Westfield; Barnstable County). Contact methods and sites vary by location; find local via 1-800-243-4636.",
    "offices_or_providers": ["Senior centers", "Councils on Aging", "Regional Aging Services Access Points", "Local agencies like Ethos (Boston), Mystic Valley Elder Services (specific North Shore communities), AgeSpan"]
  },
  "official_source": "https://www.mass.gov/info-details/serving-the-health-insurance-needs-of-everyone-shine-program",
  "gotchas": ["Not a direct service or financial benefit program—provides counseling only, not healthcare or payments; people may confuse it with MassHealth/Medicare itself", "Must be Medicare-eligible or approaching (not general elder care); for limited-income programs, separate eligibility applies", "Services free/confidential but relies on volunteers/agency staff—availability varies locally", "Open Enrollment (Oct 15-Dec 7) critical for changes", "Contact local lead for site-specific recruiting/volunteering, not central office"],
  "data_shape_notes": "no income/asset test for counseling; statewide but regionally delivered via local providers and volunteers; focuses on advocacy/eligibility screening for Medicare-related cost-saving programs rather than direct benefits"
}

{
  "name": "Massachusetts Senior Legal Helpline",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits specified for the helpline itself. Free attorney representation through referrals may require low-income eligibility (e.g., below 125% of federal poverty level for some civil legal services programs), determined by helpline advocates.[1][2][3]",
    "asset_limits": "No asset limits mentioned.",
    "other_requirements": ["Massachusetts resident", "Civil legal issues only (e.g., social security/SSI, veterans benefits, MassHealth, Medicare, consumer issues, public benefits, unemployment, foreclosures, guardianship, power of attorney, bankruptcy, evictions, landlord/tenant, utilities, family law, nursing home issues)"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal information, advice, and referral services. May assist with application for free attorney (most callers ineligible), referrals to reduced-fee or private attorneys, or provision of links/written materials via text, email, or mail. Covers civil law topics only; no representation by helpline itself.[1][2]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-342-5297 (Mon-Fri 9am-12pm)", "Download brochure/form: https://www.mass.gov/doc/senior-legal-help-line/download"],
    "processing_time": "Immediate phone assistance during hours; attorney eligibility determination and referral handled during call.",
    "waitlist": null,
    "forms": ["Senior Legal Helpline application (completed with advocate assistance for civil legal services programs)"],
    "documents": ["No specific documents listed; prepare details of legal issue for discussion"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Massachusetts residents only",
    "regional_variations": "Operated by Volunteer Lawyers Project of Boston; some listings note specific service areas (e.g., Northeast MA towns via AgeSpan), but described as statewide.[1][2]",
    "offices_or_providers": ["Volunteer Lawyers Project of Boston"]
  },
  "official_source": "https://www.mass.gov/doc/senior-legal-help-line/download",
  "gotchas": ["Most callers not eligible for free attorney; helpline provides info/referrals instead.", "Limited to civil law; excludes criminal, medical malpractice, workers’ comp, personal injury (though referrals possible).", "Phone hours only 9am-12pm Mon-Fri; no mention of online application.", "Not full representation—initial screening for other programs."],
  "data_shape_notes": "no income test for helpline access; age 60+ Massachusetts residents; free info/referrals primary, free attorney rare via referral"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; support is free for all eligible residents.[2][3]",
    "asset_limits": "No asset limits; support is free for all eligible residents.[2][3]",
    "other_requirements": ["Must reside in a nursing home, rest home, or assisted living facility in Massachusetts.[1][2][3][8]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigation and resolution of complaints related to health, safety, welfare, rights; mediation between residents and facilities; protection of resident rights; regular facility visits; education on rights and regulations; assistance with facility selection; support for resident/family councils; advocacy for systemic changes. Complaint categories include abuse/neglect, care, discharge/eviction, autonomy/rights, dietary, environment, and more. Provided by paid staff (41) and certified volunteers (199) who visit facilities routinely (e.g., weekly).[1][3][4][5][7][8]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 617-222-7495 (statewide main line to connect to local ombudsman).[2][3][6]", "Website: https://www.mass.gov/orgs/massachusetts-long-term-care-ombudsman-program (for regional contacts).[2][4]", "Local/regional offices: Contact via city/town-aligned agency or host site (17 host sites statewide; e.g., LifePath at 413-829-9234, Springwell for 22-town area).[7][8][9]", "Anyone can file a complaint on behalf of a resident (no formal application; call to report issue).[3][6]"],
    "processing_time": "Not specified; ombudsmen respond to complaints and visit facilities regularly (e.g., weekly), aiming for prompt resolution before escalation.[1][3][8]",
    "waitlist": null,
    "forms": ["No specific forms required; complaints handled via phone or in-person contact.[3]"],
    "documents": ["No documents needed to initiate; provide details of the resident and issue. Confidentiality protected unless consent given or required for abuse reporting.[4][7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents of nursing homes, rest homes, assisted living facilities across Massachusetts (covers over 683 facilities).[4]",
    "regional_variations": "Operates from 17 host sites with regional ombudsman programs (e.g., Old Colony Planning Council, AgeSpan, Springwell for 22 towns, LifePath, Bay Path Elder Services). Local offices aligned by city/town; contact main line for specific regional director or provider.[1][2][7][8][9]",
    "offices_or_providers": ["State office: 1 Ashburton, Room 517, Boston.[2]", "Regional examples: Old Colony, AgeSpan, Springwell (22 towns), LifePath (413-829-9234), and others via https://www.mass.gov/orgs/massachusetts-long-term-care-ombudsman-program.[1][2][7][8][9]"]
  },
  "official_source": "https://www.mass.gov/orgs/massachusetts-long-term-care-ombudsman-program",
  "gotchas": ["Not a regulatory or licensing agency; focuses on advocacy and mediation, not enforcement or fines.[5]", "Services only for those already residing in covered facilities—not for community-dwelling elders or pre-admission help (though some assist with facility selection).[1][5][7]", "Complaints can be anonymous/confidential, but identity may be disclosed if needed for abuse/neglect reporting to authorities.[4][7]", "Families must contact local ombudsman via main line or regional lookup, as no single statewide application.[7]", "Not a substitute for facility grievance process, which facilities must provide.[5]"],
  "data_shape_notes": "no income/asset test; residency in certified facility required; regionally delivered via 17 host sites and local agencies; free advocacy service, not financial aid or direct care"
}
